using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search capabilities using the Brave Search API.
/// Set the environment variable BRAVE_SEARCH_API_KEY with a valid API key.
/// Free tier: https://brave.com/search/api/
/// </summary>
public sealed class WebSearchTool : IDisposable
{
    private readonly HttpClient _http = new();

    public WebSearchTool(string apiKey)
    {
        _http.BaseAddress = new Uri("https://api.search.brave.com/");
        _http.DefaultRequestHeaders.Add("X-Subscription-Token", apiKey);
        _http.DefaultRequestHeaders.Add("Accept", "application/json");
    }

    [Description("Search the web for a query and return the top results with titles, URLs, and descriptions.")]
    public async Task<string> SearchAsync(
        [Description("The search query to look up on the web")] string query,
        [Description("Maximum number of results to return (1-10)")] int count = 5)
    {
        count = Math.Clamp(count, 1, 10);

        var response = await _http.GetFromJsonAsync<BraveSearchResponse>(
            $"res/v1/web/search?q={Uri.EscapeDataString(query)}&count={count}");

        if (response?.Web?.Results is not { Count: > 0 })
        {
            return "No results found.";
        }

        var lines = response.Web.Results.Select((r, i) =>
            $"[{i + 1}] {r.Title}\n    URL: {r.Url}\n    {r.Description}");

        return string.Join("\n\n", lines);
    }

    [Description("Fetch the text content of a web page given its URL. Use this after searching to read full article content.")]
    public async Task<string> FetchPageAsync(
        [Description("The full URL of the page to fetch")] string url)
    {
        try
        {
            var html = await _http.GetStringAsync(url);

            // Basic HTML-to-text: strip tags and decode entities
            var text = System.Text.RegularExpressions.Regex.Replace(html, "<[^>]+>", " ");
            text = System.Text.RegularExpressions.Regex.Replace(text, @"\s+", " ");
            text = System.Net.WebUtility.HtmlDecode(text).Trim();

            // Limit to ~4000 chars to stay within token budgets
            return text.Length > 4000 ? text[..4000] + "\n...[truncated]" : text;
        }
        catch (Exception ex)
        {
            return $"Error fetching page: {ex.Message}";
        }
    }

    public void Dispose() => _http.Dispose();
}

// Brave Search API response models
internal sealed class BraveSearchResponse
{
    [JsonPropertyName("web")]
    public BraveWebResults? Web { get; set; }
}

internal sealed class BraveWebResults
{
    [JsonPropertyName("results")]
    public List<BraveWebResult>? Results { get; set; }
}

internal sealed class BraveWebResult
{
    [JsonPropertyName("title")]
    public string Title { get; set; } = "";

    [JsonPropertyName("url")]
    public string Url { get; set; } = "";

    [JsonPropertyName("description")]
    public string Description { get; set; } = "";
}

using System.ComponentModel;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capabilities for the research agent.
/// Stores notes in memory for the duration of the session.
/// </summary>
public sealed class NoteTool
{
    private readonly List<Note> _notes = [];

    [Description("Save a research note. Use this to record key facts, quotes, or insights found during research.")]
    public string SaveNote(
        [Description("Short descriptive title for the note")] string title,
        [Description("The content of the note — facts, quotes, or insights")] string content,
        [Description("Source URL or reference where this information was found")] string source)
    {
        _notes.Add(new Note(title, content, source, DateTime.UtcNow));
        return $"Note saved: \"{title}\" ({_notes.Count} total notes)";
    }

    [Description("Retrieve all saved research notes to review findings before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        var lines = _notes.Select((n, i) =>
            $"--- Note {i + 1}: {n.Title} ---\n{n.Content}\nSource: {n.Source}");

        return string.Join("\n\n", lines);
    }

    [Description("Delete a note by its number (1-based index).")]
    public string DeleteNote(
        [Description("The 1-based index of the note to delete")] int noteNumber)
    {
        if (noteNumber < 1 || noteNumber > _notes.Count)
        {
            return $"Invalid note number. You have {_notes.Count} notes (1-{_notes.Count}).";
        }

        var removed = _notes[noteNumber - 1];
        _notes.RemoveAt(noteNumber - 1);
        return $"Deleted note: \"{removed.Title}\" ({_notes.Count} remaining)";
    }

    private sealed record Note(string Title, string Content, string Source, DateTime CreatedAt);
}

