using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using Microsoft.Agents.AI;
using Microsoft.Agents.AI.ChatCompletion;
using ResearchAgent.Tools;

var builder = Host.CreateApplicationBuilder(args);

builder.Logging.SetMinimumLevel(LogLevel.Warning);

// Resolve API keys from environment variables
var openAiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable.");

var braveKey = Environment.GetEnvironmentVariable("BRAVE_SEARCH_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the BRAVE_SEARCH_API_KEY environment variable. "
        + "Get a free key at https://brave.com/search/api/");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// Register the chat client through MEAI abstraction
builder.Services.AddChatClient(b => b
    .UseOpenAIChatClient(modelId, new OpenAI.OpenAIClient(openAiKey)));

// Register tools
