using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using Microsoft.Agents.AI;
using Microsoft.Agents.AI.ChatCompletion;
using ResearchAgent.Tools;

var builder = Host.CreateApplicationBuilder(args);

builder.Logging.SetMinimumLevel(LogLevel.Warning);

// Resolve API keys from environment variables
var openAiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable.");

var braveKey = Environment.GetEnvironmentVariable("BRAVE_SEARCH_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the BRAVE_SEARCH_API_KEY environment variable. "
        + "Get a free key at https://brave.com/search/api/");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// Register the chat client through MEAI abstraction
builder.Services.AddChatClient(b => b
    .UseOpenAIChatClient(modelId, new OpenAI.OpenAIClient(openAiKey)));

// Register tools
builder.Services.AddSingleton(new WebSearchTool(braveKey));
builder.Services.AddSingleton<NoteTool>();

using var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var searchTool = host.Services.GetRequiredService<WebSearchTool>();
var noteTool = host.Services.GetRequiredService<NoteTool>();

// Build AI functions from the tool instances
var tools = new AIFunction[]
{
    AIFunctionFactory.Create(searchTool.SearchAsync),
    AIFunctionFactory.Create(searchTool.FetchPageAsync),
    AIFunctionFactory.Create(noteTool.SaveNote),
    AIFunctionFactory.Create(noteTool.GetNotes),
    AIFunctionFactory.Create(noteTool.DeleteNote),
};

// Create the research agent
var agent = new ChatClientAgent(
    chatClient,
    "ResearchAgent",
    """
    You are a thorough research agent. When given a topic, you:
    1. Search the web for relevant information using multiple queries.
    2. Fetch and read promising pages to gather detailed information.
    3. Save key facts, insights, and quotes as notes (always include the source URL).
    4. Review your notes and perform follow-up searches to fill gaps.
    5. Once you have comprehensive notes, retrieve all notes and write a
       well-structured summary with source citations.

    Always cite your sources. Be thorough but concise in your final summary.
    """);

var chatOptions = new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
    Tools = [.. tools],
};

// Prompt the user
Console.ForegroundColor = ConsoleColor.Cyan;
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍 Research Agent              ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.ResetColor();
Console.WriteLine();
Console.Write("Enter a research topic (or 'quit' to exit): ");

while (Console.ReadLine() is { } topic && !topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
{
    if (string.IsNullOrWhiteSpace(topic))
    {
        Console.Write("\nEnter a research topic: ");
        continue;
    }

    Console.WriteLine($"\nResearching: {topic}\n");

    var history = new List<ChatMessage>
    {
        new(ChatRole.User, $"Research the following topic and provide a comprehensive summary with citations: {topic}"),
    };

    var invokeOptions = new AgentInvokeOptions
    {
        MaximumIterations = 15,
    };

