         + "Get a free key at https://brave.com/search/api/");

 var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

 builder.Services.AddSingleton(new WebSearchTool(braveKey));
 builder.Services.AddSingleton<NoteTool>();

 builder.Services.AddSingleton<IChatClient>(_ =>
     new OpenAI.OpenAIClient(openAiKey).GetChatClient(modelId).AsIChatClient());

